"""
Claude Dashboard — Session Detection & Process Tree Analysis

Cross-platform script to discover running Claude Code sessions and map them
to their containing application windows. Currently implements Windows 11
support. Linux support to be added.

Usage:
    python detect_sessions.py [--json]

Requires: psutil
"""

import argparse
import ctypes
import json
import os
import platform
import sys
from dataclasses import dataclass, field, asdict
from pathlib import Path
from typing import Optional


CLAUDE_HOME = Path.home() / ".claude"
SESSIONS_DIR = CLAUDE_HOME / "sessions"
SESSION_TRACKER_DIR = CLAUDE_HOME / "session-tracker"


@dataclass
class ContainerInfo:
    """The application containing the Claude session."""
    process_name: str = "Unknown"
    process_pid: int = 0
    container_type: str = "Unknown"  # VSCode, Terminal, GitBash, Screen, Unknown
    window_handle: int = 0
    window_title: str = ""
    vscode_ipc_handle: str = ""


@dataclass
class SessionInfo:
    """A discovered Claude Code session."""
    pid: int = 0
    session_id: str = ""
    cwd: str = ""
    started_at: int = 0
    pid_alive: bool = False
    slug: str = ""
    container: Optional[ContainerInfo] = None
    process_chain: list[str] = field(default_factory=list)


def discover_sessions() -> list[SessionInfo]:
    """Read ~/.claude/sessions/*.json to find all registered sessions."""
    sessions = []
    if not SESSIONS_DIR.exists():
        return sessions

    for session_file in SESSIONS_DIR.glob("*.json"):
        try:
            data = json.loads(session_file.read_text(encoding="utf-8"))
            session = SessionInfo(
                pid=data.get("pid", 0),
                session_id=data.get("sessionId", ""),
                cwd=data.get("cwd", ""),
                started_at=data.get("startedAt", 0),
            )
            sessions.append(session)
        except (json.JSONDecodeError, OSError) as exc:
            print(f"Warning: could not read {session_file}: {exc}", file=sys.stderr)

    return sessions


def validate_pid(pid: int) -> bool:
    """Check if a process with the given PID is still alive."""
    try:
        import psutil
        return psutil.pid_exists(pid) and psutil.Process(pid).name() == "claude.exe"
    except Exception:
        return False


def walk_process_chain(pid: int) -> list[str]:
    """Walk the parent process chain from PID to root, returning names."""
    import psutil
    chain = []
    try:
        current = psutil.Process(pid)
        while current:
            chain.append(f"{current.name()} (PID {current.pid})")
            current = current.parent()
    except (psutil.NoSuchProcess, psutil.AccessDenied):
        pass
    return chain


def detect_container_type(pid: int) -> ContainerInfo:
    """Determine the containing application for a Claude session.

    Walks the parent process chain and checks environment variables
    to identify whether Claude is running inside VS Code, a terminal
    emulator, screen, etc.
    """
    import psutil
    container = ContainerInfo()

    try:
        claude_proc = psutil.Process(pid)
        bash_proc = claude_proc.parent()
        if not bash_proc:
            return container

        # Extract only the env vars we need — avoid holding the full
        # environment in memory (may contain API keys, secrets, etc.)
        term_program = ""
        vscode_ipc = ""
        try:
            full_env = bash_proc.environ()
            term_program = full_env.get("TERM_PROGRAM", "").lower()
            vscode_ipc = full_env.get("VSCODE_GIT_IPC_HANDLE", "")
            del full_env
        except (psutil.AccessDenied, psutil.NoSuchProcess):
            pass

        # Walk up the process chain to find the containing application
        current = bash_proc
        while current:
            name = current.name().lower()

            if "code" in name and "code.exe" in name:
                container.process_name = current.name()
                container.process_pid = current.pid
                container.container_type = "VSCode"
                container.vscode_ipc_handle = vscode_ipc
                break

            if name in ("windowsterminal.exe", "wt.exe"):
                container.process_name = current.name()
                container.process_pid = current.pid
                container.container_type = "Terminal"
                break

            if name in ("cmd.exe",):
                container.process_name = current.name()
                container.process_pid = current.pid
                container.container_type = "Terminal"
                break

            if name in ("mintty.exe",):
                container.process_name = current.name()
                container.process_pid = current.pid
                container.container_type = "GitBash"
                break

            # Linux terminal emulators
            if name in (
                "gnome-terminal-server", "konsole", "xfce4-terminal",
                "alacritty", "kitty", "wezterm-gui", "terminator",
                "tilix", "xterm", "urxvt", "st",
            ):
                container.process_name = current.name()
                container.process_pid = current.pid
                container.container_type = "Terminal"
                break

            if name == "screen":
                container.process_name = current.name()
                container.process_pid = current.pid
                container.container_type = "Screen"
                # Keep walking to find the terminal hosting screen
                screen_pid = current.pid
                current = current.parent()
                continue

            current = current.parent()

        # If we identified VS Code from env but didn't find it in chain
        # (shouldn't happen, but defensive)
        if container.container_type == "Unknown" and term_program == "vscode":
            container.container_type = "VSCode"

    except (psutil.NoSuchProcess, psutil.AccessDenied):
        pass

    return container


def find_window_for_container_windows(container: ContainerInfo) -> ContainerInfo:
    """On Windows, find the window handle and title for the container process.

    For VS Code, all renderer processes are children of a single main process.
    We enumerate visible windows belonging to renderer processes and match
    by window title (which contains the workspace folder name).
    """
    if platform.system() != "Windows":
        return container

    if container.process_pid == 0:
        return container

    try:
        from ctypes import wintypes
        user32 = ctypes.windll.user32

        WNDENUMPROC = ctypes.WINFUNCTYPE(
            ctypes.c_bool, wintypes.HWND, wintypes.LPARAM
        )

        if container.container_type == "VSCode":
            # VS Code uses a multi-process architecture. The main process
            # (parent of all) spawns renderer processes that own the windows.
            # We need to find renderer processes and their windows.
            import psutil

            # Find the main VS Code process (walk up from the utility process)
            # Windows are owned by the main process, not renderers.
            main_pid = container.process_pid
            try:
                proc = psutil.Process(main_pid)
                while proc.parent() and proc.parent().name().lower() == "code.exe":
                    proc = proc.parent()
                main_pid = proc.pid
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass

            # Enumerate visible windows owned by the main VS Code process
            found_windows = []

            def enum_cb(hwnd, _):
                if user32.IsWindowVisible(hwnd):
                    pid = wintypes.DWORD()
                    user32.GetWindowThreadProcessId(hwnd, ctypes.byref(pid))
                    if pid.value == main_pid:
                        length = user32.GetWindowTextLengthW(hwnd)
                        if length > 0:
                            buf = ctypes.create_unicode_buffer(length + 1)
                            user32.GetWindowTextW(hwnd, buf, length + 1)
                            found_windows.append((hwnd, buf.value))
                return True

            user32.EnumWindows(WNDENUMPROC(enum_cb), 0)

            if found_windows:
                container.window_handle = found_windows[0][0]
                container.window_title = found_windows[0][1]

        else:
            # For non-VS Code containers, find windows owned by the
            # container process directly
            target_pid = container.process_pid
            found_windows = []

            def enum_cb_direct(hwnd, _):
                if user32.IsWindowVisible(hwnd):
                    pid = wintypes.DWORD()
                    user32.GetWindowThreadProcessId(hwnd, ctypes.byref(pid))
                    if pid.value == target_pid:
                        length = user32.GetWindowTextLengthW(hwnd)
                        if length > 0:
                            buf = ctypes.create_unicode_buffer(length + 1)
                            user32.GetWindowTextW(hwnd, buf, length + 1)
                            found_windows.append((hwnd, buf.value))
                return True

            user32.EnumWindows(WNDENUMPROC(enum_cb_direct), 0)

            if found_windows:
                container.window_handle = found_windows[0][0]
                container.window_title = found_windows[0][1]

    except Exception as exc:
        print(f"Warning: window detection failed: {exc}", file=sys.stderr)

    return container


def match_vscode_window_by_cwd(
    cwd: str, container: ContainerInfo
) -> ContainerInfo:
    """Match a VS Code window to a session by checking if the CWD appears
    in any VS Code window title.

    VS Code window titles typically contain the workspace folder name,
    e.g., 'claude-dashboard - Visual Studio Code'.
    """
    if platform.system() != "Windows":
        return container

    if container.container_type != "VSCode":
        return container

    try:
        from ctypes import wintypes
        import psutil

        user32 = ctypes.windll.user32
        WNDENUMPROC = ctypes.WINFUNCTYPE(
            ctypes.c_bool, wintypes.HWND, wintypes.LPARAM
        )

        # Get the folder name from CWD
        folder_name = Path(cwd).name.lower()

        # Find main VS Code PID — walk up from the utility/child process
        # to the top-level Code.exe (whose parent is explorer.exe).
        # Windows are owned by this main process, not by renderers.
        main_pid = container.process_pid
        try:
            proc = psutil.Process(main_pid)
            while proc.parent() and proc.parent().name().lower() == "code.exe":
                proc = proc.parent()
            main_pid = proc.pid
        except (psutil.NoSuchProcess, psutil.AccessDenied):
            pass

        # Enumerate visible windows owned by the main VS Code process
        # and match by CWD folder name appearing in the window title.
        best_match = None

        def enum_cb(hwnd, _):
            nonlocal best_match
            if user32.IsWindowVisible(hwnd):
                pid = wintypes.DWORD()
                user32.GetWindowThreadProcessId(hwnd, ctypes.byref(pid))
                if pid.value == main_pid:
                    length = user32.GetWindowTextLengthW(hwnd)
                    if length > 0:
                        buf = ctypes.create_unicode_buffer(length + 1)
                        user32.GetWindowTextW(hwnd, buf, length + 1)
                        title = buf.value
                        if folder_name in title.lower():
                            best_match = (hwnd, title, pid.value)
            return True

        user32.EnumWindows(WNDENUMPROC(enum_cb), 0)

        if best_match:
            container.window_handle = best_match[0]
            container.window_title = best_match[1]

    except Exception as exc:
        print(
            f"Warning: VS Code window matching failed: {exc}",
            file=sys.stderr,
        )

    return container


def main():
    parser = argparse.ArgumentParser(
        description="Detect running Claude Code sessions and their containers"
    )
    parser.add_argument(
        "--json", action="store_true", help="Output as JSON"
    )
    parser.add_argument(
        "--verbose", action="store_true",
        help="Include internal details (IPC handles, etc.) in output",
    )
    parser.add_argument(
        "--debug-windows", action="store_true",
        help="Enumerate all VS Code windows for diagnostics",
    )
    args = parser.parse_args()

    sessions = discover_sessions()

    for session in sessions:
        session.pid_alive = validate_pid(session.pid)
        if session.pid_alive:
            session.process_chain = walk_process_chain(session.pid)
            session.container = detect_container_type(session.pid)
            if platform.system() == "Windows":
                session.container = find_window_for_container_windows(
                    session.container
                )
                session.container = match_vscode_window_by_cwd(
                    session.cwd, session.container
                )

    if args.json:
        output = []
        for s in sessions:
            d = asdict(s)
            if not args.verbose and d.get("container"):
                d["container"].pop("vscode_ipc_handle", None)
            output.append(d)
        print(json.dumps(output, indent=2))
    else:
        for session in sessions:
            alive = "ALIVE" if session.pid_alive else "DEAD"
            print(f"Session: {session.session_id}")
            print(f"  PID:       {session.pid} ({alive})")
            print(f"  CWD:       {session.cwd}")
            print(f"  Started:   {session.started_at}")
            if session.container:
                c = session.container
                print(f"  Container: {c.container_type} ({c.process_name})")
                if c.window_title:
                    print(f"  Window:    '{c.window_title}' (HWND={c.window_handle})")
                if args.verbose and c.vscode_ipc_handle:
                    print(f"  IPC:       {c.vscode_ipc_handle}")
            if session.process_chain:
                print(f"  Chain:     {' -> '.join(session.process_chain)}")
            print()


def debug_windows():
    """Enumerate all visible windows from VS Code renderer processes.

    Diagnostic function to understand the window mapping when
    match_vscode_window_by_cwd fails to find matches.
    """
    if platform.system() != "Windows":
        print("Window debugging only supported on Windows.")
        return

    import psutil
    from ctypes import wintypes

    user32 = ctypes.windll.user32
    WNDENUMPROC = ctypes.WINFUNCTYPE(
        ctypes.c_bool, wintypes.HWND, wintypes.LPARAM
    )

    # Find main VS Code process (parent=explorer.exe)
    main_pids = []
    for proc in psutil.process_iter(["pid", "name", "ppid"]):
        if proc.info["name"] == "Code.exe":
            try:
                parent = psutil.Process(proc.info["ppid"])
                if parent.name() == "explorer.exe":
                    main_pids.append(proc.info["pid"])
            except (psutil.NoSuchProcess, psutil.AccessDenied):
                pass

    print(f"VS Code main process PIDs: {main_pids}")

    for main_pid in main_pids:
        main_proc = psutil.Process(main_pid)
        print(f"\nMain PID {main_pid}: {' '.join(main_proc.cmdline()[:3])}")

        # Categorize children
        renderer_pids = set()
        all_child_types = {}
        for child in main_proc.children(recursive=True):
            if child.name().lower() == "code.exe":
                cmd_str = " ".join(child.cmdline())
                for flag in ("--type=renderer", "--type=utility",
                             "--type=gpu-process", "--type=zygote",
                             "--type=crashpad-handler"):
                    if flag in cmd_str:
                        ptype = flag.split("=")[1]
                        all_child_types.setdefault(ptype, []).append(child.pid)
                        if ptype == "renderer":
                            renderer_pids.add(child.pid)
                        break
                else:
                    all_child_types.setdefault("unknown", []).append(child.pid)

        print(f"  Child process types:")
        for ptype, pids in sorted(all_child_types.items()):
            print(f"    {ptype}: {len(pids)} processes {pids}")

        # Enumerate ALL visible windows from ALL Code.exe children
        all_code_pids = set()
        for child in main_proc.children(recursive=True):
            if child.name().lower() == "code.exe":
                all_code_pids.add(child.pid)
        all_code_pids.add(main_pid)

        all_windows = []

        def enum_cb(hwnd, _):
            if user32.IsWindowVisible(hwnd):
                pid = wintypes.DWORD()
                user32.GetWindowThreadProcessId(hwnd, ctypes.byref(pid))
                if pid.value in all_code_pids:
                    length = user32.GetWindowTextLengthW(hwnd)
                    title = ""
                    if length > 0:
                        buf = ctypes.create_unicode_buffer(length + 1)
                        user32.GetWindowTextW(hwnd, buf, length + 1)
                        title = buf.value
                    all_windows.append((hwnd, title, pid.value))
            return True

        user32.EnumWindows(WNDENUMPROC(enum_cb), 0)

        print(f"\n  Visible windows from Code.exe processes ({len(all_windows)} total):")
        for hwnd, title, wpid in all_windows:
            in_renderer = "RENDERER" if wpid in renderer_pids else "other"
            label = title if title else "(no title)"
            print(f"    HWND={hwnd} PID={wpid} [{in_renderer}] '{label}'")

        # Also show windows from the main process itself
        print(f"\n  Renderer PIDs specifically: {renderer_pids}")


def foreground_window(hwnd: int) -> bool:
    """Bring a window to the foreground on Windows.

    Uses SetForegroundWindow with fallback strategies for when the
    calling process doesn't have foreground permission.
    """
    if platform.system() != "Windows":
        print("Foreground not implemented for this platform.", file=sys.stderr)
        return False

    from ctypes import wintypes

    user32 = ctypes.windll.user32

    # If the window is minimized, restore it first
    SW_RESTORE = 9
    if user32.IsIconic(hwnd):
        user32.ShowWindow(hwnd, SW_RESTORE)

    # Attempt SetForegroundWindow directly
    result = user32.SetForegroundWindow(hwnd)
    if result:
        return True

    # Fallback: use AllowSetForegroundWindow + Alt key trick.
    # Windows restricts SetForegroundWindow to the foreground process.
    # Simulating an Alt keypress can work around this.
    VK_ALT = 0x12
    KEYEVENTF_EXTENDEDKEY = 0x0001
    KEYEVENTF_KEYUP = 0x0002

    user32.keybd_event(VK_ALT, 0, KEYEVENTF_EXTENDEDKEY, 0)
    result = user32.SetForegroundWindow(hwnd)
    user32.keybd_event(VK_ALT, 0, KEYEVENTF_EXTENDEDKEY | KEYEVENTF_KEYUP, 0)

    return bool(result)


def foreground_session(session_id_prefix: str):
    """Find a session by ID prefix and foreground its containing window."""
    sessions = discover_sessions()

    matched = None
    for session in sessions:
        if session.session_id.startswith(session_id_prefix):
            matched = session
            break

    if not matched:
        print(f"No session found matching '{session_id_prefix}'")
        return

    matched.pid_alive = validate_pid(matched.pid)
    if not matched.pid_alive:
        print(f"Session {matched.session_id} PID {matched.pid} is dead.")
        return

    matched.container = detect_container_type(matched.pid)
    if platform.system() == "Windows":
        matched.container = match_vscode_window_by_cwd(
            matched.cwd, matched.container
        )

    if not matched.container or matched.container.window_handle == 0:
        print(f"Could not find window for session {matched.session_id}")
        return

    hwnd = matched.container.window_handle
    title = matched.container.window_title
    print(f"Foregrounding: '{title}' (HWND={hwnd})")
    success = foreground_window(hwnd)
    print(f"Result: {'success' if success else 'failed'}")


if __name__ == "__main__":
    import sys as _sys
    if "--debug-windows" in _sys.argv:
        debug_windows()
    elif "--foreground" in _sys.argv:
        idx = _sys.argv.index("--foreground")
        if idx + 1 < len(_sys.argv):
            foreground_session(_sys.argv[idx + 1])
        else:
            print("Usage: --foreground <session_id_prefix>")
    else:
        main()
